import re, pathlib
p = pathlib.Path('/Users/gbang/Downloads/algora/workspace/4db3531e-3c7a-4d65-b4d5-eb027e21370a_hld/_response.md')
md = p.read_text(encoding='utf-8')
print("CHARS:", len(md))

# headings
headings = re.findall(r'(?m)^## (\d+)\. (.+)$', md)
print("HEADINGS COUNT:", len(headings))
for n,h in headings:
    print(f"  ## {n}. {h}")

# mermaid blocks
blocks = re.findall(r'```mermaid\n(.*?)```', md, flags=re.DOTALL)
print("\nMERMAID BLOCKS:", len(blocks))

# scan mermaid edge/node labels for breaking chars
# breaking chars inside labels: ( ) [ ] | : / " < > ; { }
# but [ ] are node delimiters and | are edge-label delimiters and [( )] are cylinders, [[ ]] queues
# so we extract text INSIDE [..], |"..."| , and check for offenders
bad = []
for i,b in enumerate(blocks):
    # node labels: [Label], [(Label)], [[Label]]
    for m in re.finditer(r'\[+\(?([^\[\]\(\)]+)\)?\]+', b):
        lbl = m.group(1)
        for ch in '():/";<>{}':
            if ch in lbl:
                bad.append((i, 'node', repr(lbl), ch))
    # edge labels: |"..."| or |...|
    for m in re.finditer(r'\|"?([^|"]+)"?\|', b):
        lbl = m.group(1)
        for ch in '():/;<>{}':
            if ch in lbl:
                bad.append((i, 'edge', repr(lbl), ch))
if bad:
    print("\nPOTENTIAL BREAKING CHARS:")
    for x in bad: print("  ", x)
else:
    print("\nNo breaking chars found in node/edge labels.")
